#include <stdio.h>
#include <pthread.h>

static int total = 0;
static pthread_mutex_t lock = PTHREAD_MUTEX_INITIALIZER;

typedef struct { int amount; } arg_t;

void *worker(void *arg) {
    int amount = ((arg_t *)arg)->amount;
    pthread_mutex_lock(&lock);
    if (amount < 0) {
        return NULL;   // bug: lock is still held here
    }
    total += amount;
    pthread_mutex_unlock(&lock);
    return NULL;
}

int main(void) {
    arg_t args[4] = {{5}, {15}, {-1}, {25}};
    pthread_t threads[4];
    for (int i = 0; i < 4; i++) {
        pthread_create(&threads[i], NULL, worker, &args[i]);
    }
    for (int i = 0; i < 4; i++) {
        pthread_join(threads[i], NULL);
    }
    printf("Total: %d\n", total);
    return 0;
}
